use crate::body::RigidBodySet;
use crate::contact::ContactTracker;
use crate::contact_constraint::ContactConstraintSet;
use crate::solver_body::SolverBodySet;

/// Blueprint-style solver loop with substepping:
/// Each outer iteration is a full substep that includes:
///   1. Apply force increments to solver velocities
///   2. Clear PGS λ (per substep — avoids carrying full-frame impulses into the next frame)
///   3. Update constraints (recompute penetration + RHS from current poses)
///   4. PGS solve with bias (position correction + restitution)
///   5. Integrate positions using corrected velocities
///
/// Substepping refreshes penetration each substep; cross-frame warmstart was removed because
/// it re-applied accumulated λ and could spike stacks.
pub fn solve(
    solver_bodies: &mut SolverBodySet,
    constraints: &mut ContactConstraintSet,
    _tracker: &mut ContactTracker,
    num_substeps: usize,
    num_pgs_iterations: usize,
    substep_dt: f32,
    block_solver: bool,
    bodies: &mut RigidBodySet,
) {
    let frame_dt = substep_dt * num_substeps as f32;
    let mut clamp_events: u32 = 0;

    for _substep in 0..num_substeps {
        solver_bodies.apply_force_increments();

        constraints.clear_impulses();

        constraints.update(solver_bodies, substep_dt, frame_dt);

        for _inner in 0..num_pgs_iterations {
            constraints.solve(solver_bodies, block_solver, &mut clamp_events);
        }

        solver_bodies.integrate_positions(substep_dt);
    }

    constraints.finalize_impulse_diagnostics(clamp_events);

    solver_bodies.apply_damping(substep_dt * num_substeps as f32);

    solver_bodies.writeback_to_bodies(bodies);
}
